# ── DRAKEN DIGEST DEPLOY SCRIPT ──
# Run from any directory. Assumes repo at C:\Draken\draken.info\

$repoRoot = "C:\Draken\draken.info"
$digestDir = "$repoRoot\digest\q2-2026"
$digestFile = "$digestDir\index.html"
$systemJson = "$repoRoot\static\data\system.json"
$buildJs = "$repoRoot\build.js"

Write-Host "=== Draken Digest Deploy ===" -ForegroundColor Green

# ── Step 1: Write digest index.html ──
Write-Host "Step 1: Writing digest/q2-2026/index.html ..." -ForegroundColor Cyan
New-Item -ItemType Directory -Force -Path $digestDir | Out-Null

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes($digestFile, $bytes)
$size = (Get-Item $digestFile).Length
Write-Host "  Written: $size bytes" -ForegroundColor Green

# ── Step 2: Patch build.js — add buildDigestPages() ──
Write-Host "Step 2: Patching build.js ..." -ForegroundColor Cyan
$bjs = Get-Content $buildJs -Raw

if ($bjs -notmatch 'buildDigestPages') {
    # Insert buildDigestPages function after buildSlaskPage function body ends
    $digestFn = @'

// ── DIGEST pages (self-contained standalone HTML, one dir per issue) ──
function buildDigestPages() {
  const src = path.join(__dirname, 'digest');
  const dst = path.join(DIST_DIR, 'digest');
  if (!fs.existsSync(src)) { console.log('  · digest/ source not present, skipping'); return; }
  copyDirSync(src, dst);
  let count = 0;
  for (const e of fs.readdirSync(src, { withFileTypes: true })) {
    if (e.isDirectory() && fs.existsSync(path.join(src, e.name, 'index.html'))) count++;
  }
  console.log('  \u2713 digest/ (' + count + ' issue' + (count !== 1 ? 's' : '') + ')');
}
'@
    # Add after the closing brace of buildSlaskPage — find last occurrence of the pattern
    $insertAfter = "  console.log('  \u2713 slask/ (dynamic, ' + fileCount + ' static files)');"
    $bjs = $bjs -replace [regex]::Escape($insertAfter), ($insertAfter + $digestFn)
    
    # Also add the call in build() after buildSlaskPage(baseTpl)
    $bjs = $bjs -replace 'buildSlaskPage\(baseTpl\);', "buildSlaskPage(baseTpl);`n  buildDigestPages();"
    
    # Add sitemap entry
    $bjs = $bjs -replace "posts\.map\(p =>", "`\`<url><loc>\${b}/digest/q2-2026/</loc><priority>0.8</priority></url>\n\` +`n    posts.map(p =>"
    
    Set-Content -Path $buildJs -Value $bjs -Encoding UTF8 -NoNewline
    Write-Host "  build.js patched (buildDigestPages added)" -ForegroundColor Green
} else {
    Write-Host "  build.js already has buildDigestPages, skipping" -ForegroundColor Yellow
}

