Set-Content -Path $systemJson -Value $sysJson -Encoding UTF8
Write-Host "  system.json updated (21 publications, phase ALPHA, all 18 layers active)" -ForegroundColor Green

# ── Step 4: Run the build ──
Write-Host "Step 4: Running node build.js ..." -ForegroundColor Cyan
Set-Location $repoRoot
