# ── Step 5: Verify ──
Write-Host "`nStep 5: Verifying output ..." -ForegroundColor Cyan
$checks = @(
    "$repoRoot\dist\digest\q2-2026\index.html",
    "$repoRoot\dist\index.html",
    "$repoRoot\dist\sitemap.xml"
)
foreach ($f in $checks) {
    if (Test-Path $f) {
        $sz = (Get-Item $f).Length
        Write-Host "  OK  $f ($sz bytes)" -ForegroundColor Green
    } else {
        Write-Host "  MISSING  $f" -ForegroundColor Red
    }
}

